class HistoryManager:
    """历史记录管理器 - 记录所有翻译任务"""
    
    @staticmethod
    def get_history_path():
        """获取历史记录文件路径"""
        home = Path.home()
        return home / "pdf2zh_history.json"
    
    @staticmethod
    def load_history():
        """加载历史记录"""
        history_path = HistoryManager.get_history_path()
        if history_path.exists():
            try:
                with open(history_path, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    return data.get('history', [])
            except Exception as e:
                print(f"加载历史记录失败: {e}")
                return []
        return []
    
    @staticmethod
    def save_history(history_list: list):
        """保存历史记录"""
        history_path = HistoryManager.get_history_path()
        try:
            with open(history_path, 'w', encoding='utf-8') as f:
                json.dump({'history': history_list}, f, indent=2, ensure_ascii=False)
            return True
        except Exception as e:
            print(f"保存历史记录失败: {e}")
            return False
    
    @staticmethod
    def add_record(record: dict):
        """添加一条历史记录"""
        history = HistoryManager.load_history()
        history.insert(0, record)  # 最新记录放在最前面
        # 限制历史记录数量为 100 条
        if len(history) > 100:
            history = history[:100]
        HistoryManager.save_history(history)
    
    @staticmethod
    def delete_record(record_id: str):
        """删除指定的历史记录"""
        history = HistoryManager.load_history()
        history = [r for r in history if r.get('id') != record_id]
        HistoryManager.save_history(history)
    
    @staticmethod
    def clear_history():
        """清空所有历史记录"""
        HistoryManager.save_history([])


class UserConfigManager:
    """用户配置管理器 - 保存和加载用户偏好设置"""
    
    @staticmethod
    def get_config_path():
        """获取配置文件路径"""
        home = Path.home()
        return home / "pdf2zh_gui_config.json"
    
    @staticmethod
    def load_config():
        """加载配置"""
        config_path = UserConfigManager.get_config_path()
        if config_path.exists():
            try:
                with open(config_path, 'r', encoding='utf-8') as f:
                    return json.load(f)
            except Exception as e:
                print(f"加载配置失败: {e}")
                return {}
        return {}
    
    @staticmethod
    def save_config(config: dict):
        """保存配置"""
        config_path = UserConfigManager.get_config_path()
        try:
            with open(config_path, 'w', encoding='utf-8') as f:
                json.dump(config, f, indent=2, ensure_ascii=False)
            return True
        except Exception as e:
            print(f"保存配置失败: {e}")
            return False
    
    @staticmethod
    def encode_sensitive(value: str) -> str:
        """简单编码敏感信息（Base64）"""
        if not value:
            return ""
        return base64.b64encode(value.encode('utf-8')).decode('utf-8')
    
    @staticmethod
    def decode_sensitive(value: str) -> str:
        """解码敏感信息"""
        if not value:
            return ""
        try:
            return base64.b64decode(value.encode('utf-8')).decode('utf-8')
        except:
            return ""


class PageCache:
    """页面渲染缓存 - LRU策略"""
    def __init__(self, max_size=10):
        self.cache = OrderedDict()
        self.max_size = max_size
    
    def get(self, page_num, zoom_level):
        """获取缓存的页面"""
        key = (page_num, round(zoom_level, 2))  # 四舍五入避免浮点数精度问题
        if key in self.cache:
            # 移到末尾(最近使用)
            self.cache.move_to_end(key)
            return self.cache[key]
        return None
    
    def put(self, page_num, zoom_level, pixmap):
        """添加页面到缓存"""
        key = (page_num, round(zoom_level, 2))
        if len(self.cache) >= self.max_size:
            # 移除最久未使用的
            self.cache.popitem(last=False)
        self.cache[key] = pixmap
    
    def clear(self):
        """清空缓存"""
        self.cache.clear()
    
    def remove_zoom_level(self, zoom_level):
        """移除特定缩放级别的所有缓存"""
        zoom_key = round(zoom_level, 2)
        keys_to_remove = [k for k in self.cache.keys() if k[1] == zoom_key]
        for key in keys_to_remove:
            del self.cache[key]


class PreloadWorker(QThread):
    """后台预加载线程"""
    page_loaded = pyqtSignal(int, float, object)  # page_num, zoom_level, pixmap
    
    def __init__(self, doc, page_nums, zoom_level):
        super().__init__()
        self.doc = doc
        self.page_nums = page_nums
        self.zoom_level = zoom_level
        self._stopped = False
    
    def run(self):
        """预加载指定页面"""
        try:
            import fitz
            for page_num in self.page_nums:
                if self._stopped:
                    break
                    
                if 0 <= page_num < len(self.doc):
                    page = self.doc[page_num]
                    mat = fitz.Matrix(self.zoom_level, self.zoom_level)
                    pix = page.get_pixmap(matrix=mat)
                    
                    img = QImage(pix.samples, pix.width, pix.height,
                               pix.stride, QImage.Format_RGB888)
                    pixmap = QPixmap.fromImage(img)
                    
                    if not self._stopped:
                        self.page_loaded.emit(page_num, self.zoom_level, pixmap)
        except Exception as e:
            print(f"预加载错误: {e}")
    
    def stop(self):
        """停止预加载"""
        self._stopped = True


class TranslateWorker(QThread):
    """翻译工作线程"""
    progress_updated = pyqtSignal(int, str)  # 进度百分比, 描述
    translation_finished = pyqtSignal(str, str, str)  # mono文件路径, dual文件路径, side_by_side文件路径
    translation_error = pyqtSignal(str)  # 错误信息
    
    def __init__(self, params: dict):
        super().__init__()
        self.params = params
        self.cancelled = False
    
    def create_side_by_side_pdf(self, original_path: str, translated_path: str, output_path: str):
        """创建双语并排 PDF（左边原文，右边译文）"""
        try:
            import fitz  # PyMuPDF
            
            doc_original = fitz.open(original_path)
            doc_translated = fitz.open(translated_path)
            doc_output = fitz.open()
            
            page_count = min(len(doc_original), len(doc_translated))
            
            for i in range(page_count):
                # 获取原始页面和翻译页面
                page_orig = doc_original[i]
                page_trans = doc_translated[i]
                
                # 获取页面尺寸
                orig_rect = page_orig.rect
                trans_rect = page_trans.rect
                
                # 计算新页面尺寸（宽度翻倍，高度取最大值）
                new_width = orig_rect.width + trans_rect.width
                new_height = max(orig_rect.height, trans_rect.height)
                
                # 创建新页面
                new_page = doc_output.new_page(width=new_width, height=new_height)
                
                # 在左侧插入原文页面
                new_page.show_pdf_page(
                    fitz.Rect(0, 0, orig_rect.width, orig_rect.height),
                    doc_original,
                    i
                )
                
                # 在右侧插入译文页面
                new_page.show_pdf_page(
                    fitz.Rect(orig_rect.width, 0, new_width, trans_rect.height),
                    doc_translated,
                    i
                )
                
                # 添加分隔线
                new_page.draw_line(
                    fitz.Point(orig_rect.width, 0),
                    fitz.Point(orig_rect.width, new_height),
                    color=(0.7, 0.7, 0.7),
                    width=1
                )
            
            # 保存输出文件
            doc_output.save(output_path, deflate=True, garbage=3)
            
            doc_original.close()
            doc_translated.close()
            doc_output.close()
            
            return True
        except Exception as e:
            import traceback
            print(f"创建双语并排 PDF 失败: {e}\n{traceback.format_exc()}")
            return False
    
    def run(self):
        try:
            import asyncio
            # 延迟导入 pdf2zh 核心模块
            from pdf2zh.high_level import translate

            # 尝试导入 doclayout，如果失败则继续
            try:
                from pdf2zh.doclayout import ModelInstance, DocLayoutModel
                model_available = True
            except Exception as e:
                self.progress_updated.emit(0, f"AI 布局检测不可用: {e}")
                ModelInstance = None
                DocLayoutModel = None
                model_available = False

            import tqdm

            self.cancellation_event = asyncio.Event()

            # 初始化模型（如果可用）
            if model_available and ModelInstance.value is None:
                self.progress_updated.emit(0, "正在加载 AI 布局检测模型...")
                try:
                    ModelInstance.value = DocLayoutModel.load_available()
                    self.progress_updated.emit(0, "AI 布局检测已启用 ✓")
                except Exception as e:
                    self.progress_updated.emit(0, f"AI 模型加载失败: {e}")
                    ModelInstance.value = None
            elif model_available and ModelInstance.value is not None:
                self.progress_updated.emit(0, "AI 布局检测已启用 ✓")
            
            output = Path("pdf2zh_files")
            output.mkdir(parents=True, exist_ok=True)
            
            file_path = self.params['file_path']
            filename = os.path.splitext(os.path.basename(file_path))[0]

            # 生成唯一文件名，避免覆盖之前的翻译结果
            base_filename = filename
            counter = 1
            while (output / f"{base_filename}-mono.pdf").exists() or (output / f"{base_filename}-dual.pdf").exists():
                base_filename = f"{filename}({counter})"
                counter += 1

            # 复制文件到输出目录
            file_raw = output / f"{base_filename}.pdf"
            if str(file_path) != str(file_raw):
                shutil.copy(file_path, file_raw)

            file_mono = output / f"{base_filename}-mono.pdf"
            file_dual = output / f"{base_filename}-dual.pdf"
            file_side_by_side = output / f"{base_filename}-side_by_side.pdf"

            translator = self.params['translator']
            output_mode = self.params.get('output_mode', 'dual')

            def progress_callback(t: tqdm.tqdm):
                if self.cancelled:
                    self.cancellation_event.set()
                    return
                desc = getattr(t, "desc", "翻译中...")
                if desc == "":
                    desc = "翻译中..."
                percent = int(t.n / t.total * 100) if t.total > 0 else 0
                self.progress_updated.emit(percent, desc)
            
            chunk_enabled = self.params.get('chunk_enabled', False)
            chunk_size = self.params.get('chunk_size', 50)
            chunk_delay = self.params.get('chunk_delay', 10)
            user_pages = self.params['pages']

            base_param = {
                "files": [str(file_raw)],
                "lang_in": self.params['lang_from'],
                "lang_out": self.params['lang_to'],
                "service": translator.name,
                "output": output,
                "thread": self.params['threads'],
                "callback": progress_callback,
                "cancellation_event": self.cancellation_event,
                "envs": self.params.get('envs', {}),
                "prompt": self.params.get('prompt'),
                "skip_subset_fonts": self.params.get('skip_subset_fonts', False),
                "ignore_cache": self.params.get('ignore_cache', False),
                "vfont": self.params.get('vfont', ''),
                "model": ModelInstance.value if model_available else None,
                "scan_mode": self.params.get('scan_mode', False),
            }

            if chunk_enabled and user_pages is None:
                # 分块翻译模式：获取总页数，按 chunk_size 分块
                import fitz as chunk_fitz
                doc_temp = chunk_fitz.open(str(file_raw))
                total_pages = len(doc_temp)
                doc_temp.close()

                num_chunks = (total_pages + chunk_size - 1) // chunk_size
                import time

                for chunk_idx in range(num_chunks):
                    if self.cancelled:
                        break
                    start_page = chunk_idx * chunk_size
                    end_page = min(start_page + chunk_size, total_pages)
                    chunk_pages = list(range(start_page, end_page))

                    self.progress_updated.emit(
                        int(chunk_idx / num_chunks * 100),
                        f"分块翻译: 第 {chunk_idx + 1}/{num_chunks} 块 (第 {start_page + 1}-{end_page} 页)"
                    )

                    base_param["pages"] = chunk_pages
                    translate(**base_param)

                    # 块间暂停，避免翻译服务限流
                    if chunk_delay > 0 and chunk_idx < num_chunks - 1 and not self.cancelled:
                        self.progress_updated.emit(
                            int((chunk_idx + 1) / num_chunks * 100),
                            f"暂停 {chunk_delay} 秒，避免限流..."
                        )
                        for _ in range(chunk_delay):
                            if self.cancelled:
                                break
                            time.sleep(1)

                # 最终：用所有页面生成完整输出（利用缓存，速度很快）
                if not self.cancelled:
                    self.progress_updated.emit(95, "正在生成完整输出文件...")
                    base_param["pages"] = None
                    translate(**base_param)
            else:
                # 普通模式：一次性翻译
                base_param["pages"] = user_pages
                translate(**base_param)
            
            # 如果需要生成双语并排版本
            side_by_side_path = ""
            if output_mode == 'side_by_side' and file_mono.exists() and file_raw.exists():
                self.progress_updated.emit(95, "正在生成双语并排版本...")
                if self.create_side_by_side_pdf(str(file_raw), str(file_mono), str(file_side_by_side)):
                    side_by_side_path = str(file_side_by_side)
            
            if file_mono.exists() and file_dual.exists():
                self.translation_finished.emit(str(file_mono), str(file_dual), side_by_side_path)
            else:
                self.translation_error.emit("翻译完成但未生成输出文件")
                
        except Exception as e:
            import traceback
            self.translation_error.emit(f"{str(e)}\n\n{traceback.format_exc()}")
    
    def cancel(self):
        self.cancelled = True
        if hasattr(self, 'cancellation_event'):
            self.cancellation_event.set()


class BatchTranslateWorker(QThread):
    """批量翻译工作线程"""
    # 信号定义
    batch_progress = pyqtSignal(int, int, str)  # 当前文件索引, 总文件数, 当前文件名
    file_progress = pyqtSignal(int, str)  # 当前文件进度百分比, 描述
    file_finished = pyqtSignal(str, str, str, str)  # 文件名, mono路径, dual路径, side_by_side路径
    file_error = pyqtSignal(str, str)  # 文件名, 错误信息
    batch_finished = pyqtSignal(int, int)  # 成功数, 失败数
    
    def __init__(self, file_list: list, params: dict):
        super().__init__()
        self.file_list = file_list
        self.params = params
        self.cancelled = False
        self.success_count = 0
        self.error_count = 0
    
    def create_side_by_side_pdf(self, original_path: str, translated_path: str, output_path: str):
        """创建双语并排 PDF"""
        try:
            import fitz
            
            doc_original = fitz.open(original_path)
            doc_translated = fitz.open(translated_path)
            doc_output = fitz.open()
            
            page_count = min(len(doc_original), len(doc_translated))
            
            for i in range(page_count):
                page_orig = doc_original[i]
                page_trans = doc_translated[i]
                
                orig_rect = page_orig.rect
                trans_rect = page_trans.rect
                
                new_width = orig_rect.width + trans_rect.width
                new_height = max(orig_rect.height, trans_rect.height)
                
                new_page = doc_output.new_page(width=new_width, height=new_height)
                
                new_page.show_pdf_page(
                    fitz.Rect(0, 0, orig_rect.width, orig_rect.height),
                    doc_original, i
                )
                
                new_page.show_pdf_page(
                    fitz.Rect(orig_rect.width, 0, new_width, trans_rect.height),
                    doc_translated, i
                )
                
                new_page.draw_line(
                    fitz.Point(orig_rect.width, 0),
                    fitz.Point(orig_rect.width, new_height),
                    color=(0.7, 0.7, 0.7), width=1
                )
            
            doc_output.save(output_path, deflate=True, garbage=3)
            doc_original.close()
            doc_translated.close()
            doc_output.close()
            return True
        except Exception as e:
            print(f"创建双语并排 PDF 失败: {e}")
            return False
    
    def translate_single_file(self, file_path: str, file_index: int):
        """翻译单个文件"""
        import asyncio
        from pdf2zh.high_level import translate
        import tqdm

        # 尝试导入 doclayout，如果失败则继续
        try:
            from pdf2zh.doclayout import ModelInstance, DocLayoutModel
            model_available = True
        except Exception as e:
            print(f"警告: 无法加载文档布局模型: {e}")
            ModelInstance = None
            DocLayoutModel = None
            model_available = False

        filename = os.path.splitext(os.path.basename(file_path))[0]
        self.batch_progress.emit(file_index + 1, len(self.file_list), filename)

        try:
            cancellation_event = asyncio.Event()

            # 初始化模型（如果可用）
            if model_available and ModelInstance.value is None:
                self.file_progress.emit(0, "正在加载文档布局模型...")
                try:
                    ModelInstance.value = DocLayoutModel.load_available()
                except Exception as e:
                    print(f"警告: 模型加载失败: {e}")
                    ModelInstance.value = None
            
            output = Path("pdf2zh_files")
            output.mkdir(parents=True, exist_ok=True)

            # 生成唯一文件名，避免覆盖之前的翻译结果
            base_filename = filename
            counter = 1
            while (output / f"{base_filename}-mono.pdf").exists() or (output / f"{base_filename}-dual.pdf").exists():
                base_filename = f"{filename}({counter})"
                counter += 1

            file_raw = output / f"{base_filename}.pdf"
            if str(file_path) != str(file_raw):
                shutil.copy(file_path, file_raw)

            file_mono = output / f"{base_filename}-mono.pdf"
            file_dual = output / f"{base_filename}-dual.pdf"
            file_side_by_side = output / f"{base_filename}-side_by_side.pdf"

            translator = self.params['translator']
            output_mode = self.params.get('output_mode', 'dual')
            
            def progress_callback(t: tqdm.tqdm):
                if self.cancelled:
                    cancellation_event.set()
                    return
                desc = getattr(t, "desc", "翻译中...")
                if desc == "":
                    desc = "翻译中..."
                percent = int(t.n / t.total * 100) if t.total > 0 else 0
                self.file_progress.emit(percent, f"{filename}: {desc}")
            
            param = {
                "files": [str(file_raw)],
                "pages": self.params['pages'],
                "lang_in": self.params['lang_from'],
                "lang_out": self.params['lang_to'],
                "service": translator.name,
                "output": output,
                "thread": self.params['threads'],
                "callback": progress_callback,
                "cancellation_event": cancellation_event,
                "envs": self.params.get('envs', {}),
                "prompt": self.params.get('prompt'),
                "skip_subset_fonts": self.params.get('skip_subset_fonts', False),
                "ignore_cache": self.params.get('ignore_cache', False),
                "vfont": self.params.get('vfont', ''),
                "model": ModelInstance.value if model_available else None,
                "scan_mode": self.params.get('scan_mode', False),
            }

            translate(**param)
            
            # 生成双语并排版本
            side_by_side_path = ""
            if output_mode == 'side_by_side' and file_mono.exists() and file_raw.exists():
                self.file_progress.emit(95, f"{filename}: 正在生成双语并排版本...")
                if self.create_side_by_side_pdf(str(file_raw), str(file_mono), str(file_side_by_side)):
                    side_by_side_path = str(file_side_by_side)
            
            if file_mono.exists() and file_dual.exists():
                self.file_finished.emit(filename, str(file_mono), str(file_dual), side_by_side_path)
                self.success_count += 1
            else:
                self.file_error.emit(filename, "翻译完成但未生成输出文件")
                self.error_count += 1
                
        except Exception as e:
            import traceback
            self.file_error.emit(filename, f"{str(e)}\n{traceback.format_exc()}")
            self.error_count += 1
    
    def run(self):
        """执行批量翻译"""
        for i, file_path in enumerate(self.file_list):
            if self.cancelled:
                break
            self.translate_single_file(file_path, i)
        
        self.batch_finished.emit(self.success_count, self.error_count)
    
    def cancel(self):
        self.cancelled = True


class PDFPreviewWidget(QWidget):
    """PDF 预览组件 - 支持缩放和滚轮翻页"""
    def __init__(self, parent=None):
        super().__init__(parent)
        self.main_window = parent  # 保存主窗口引用
        self.current_page = 0
        self.total_pages = 0
        self.doc = None
        self.zoom_level = 1.5  # 默认缩放级别
        self.min_zoom = 0.5
        self.max_zoom = 5.0
        self.zoom_step = 0.1
        
        # 性能优化: 页面缓存和预加载
        self.page_cache = PageCache(max_size=10)
        self.preload_worker = None
        
        self.setup_ui()
    
    def setup_ui(self):
        # 主布局改为水平布局以支持缩略图面板
        main_layout = QHBoxLayout(self)
        
        # 左侧缩略图面板
        self.thumbnail_panel = QWidget()
        self.thumbnail_panel.setMaximumWidth(200)
        self.thumbnail_panel.setVisible(False)  # 默认隐藏
        thumbnail_layout = QVBoxLayout(self.thumbnail_panel)
        thumbnail_layout.setContentsMargins(5, 5, 5, 5)
        
        # 缩略图标题
        thumb_label = QLabel("页面缩略图")
        thumb_label.setFont(QFont("Arial", 10, QFont.Bold))
        thumb_label.setAlignment(Qt.AlignCenter)
        thumbnail_layout.addWidget(thumb_label)
        
        # 缩略图列表
        self.thumbnail_list = QListWidget()
        self.thumbnail_list.setViewMode(QListWidget.IconMode)
        self.thumbnail_list.setIconSize(QSize(150, 200))
        self.thumbnail_list.setResizeMode(QListWidget.Adjust)
        self.thumbnail_list.setSpacing(5)
        self.thumbnail_list.itemClicked.connect(self.on_thumbnail_clicked)
        thumbnail_layout.addWidget(self.thumbnail_list)
        
        main_layout.addWidget(self.thumbnail_panel)
        
        # 右侧预览区域容器
        preview_container = QWidget()
        layout = QVBoxLayout(preview_container)
        layout.setContentsMargins(0, 0, 0, 0)
        
        # 预览区域
        self.scroll_area = QScrollArea()
        self.scroll_area.setWidgetResizable(False)  # 改为False以支持缩放
        self.image_label = QLabel("请选择 PDF 文件")
        self.image_label.setAlignment(Qt.AlignCenter)
        self.image_label.setStyleSheet("background-color: #f0f0f0; border: 1px solid #ccc;")
        self.scroll_area.setWidget(self.image_label)
        
        # 安装事件过滤器以捕获滚轮事件
        self.scroll_area.viewport().installEventFilter(self)
        
        layout.addWidget(self.scroll_area)
        
        # 页面导航和缩放控制
        nav_layout = QHBoxLayout()
        
        # 缩放控制
        self.zoom_out_btn = QPushButton("缩小 (-)")
        self.zoom_out_btn.clicked.connect(self.zoom_out)
        self.zoom_label = QLabel("100%")
        self.zoom_in_btn = QPushButton("放大 (+)")
        self.zoom_in_btn.clicked.connect(self.zoom_in)
        self.reset_zoom_btn = QPushButton("重置")
        self.reset_zoom_btn.clicked.connect(self.reset_zoom)
        
        nav_layout.addWidget(self.zoom_out_btn)
        nav_layout.addWidget(self.zoom_label)
        nav_layout.addWidget(self.zoom_in_btn)
        nav_layout.addWidget(self.reset_zoom_btn)
        nav_layout.addStretch()
        
        # 页面导航
        self.prev_btn = QPushButton("上一页")
        self.prev_btn.clicked.connect(self.prev_page)
        
        # 页码跳转输入框
        self.page_input = QSpinBox()
        self.page_input.setMinimum(1)
        self.page_input.setMaximum(1)
        self.page_input.setPrefix("跳转: ")
        self.page_input.valueChanged.connect(self.jump_to_page)
        self.page_input.setFixedWidth(100)
        self.page_input.setToolTip("输入页码直接跳转 (Ctrl+G)")
        
        self.page_label = QLabel("0 / 0")
        self.next_btn = QPushButton("下一页")
        self.next_btn.clicked.connect(self.next_page)
        
        nav_layout.addWidget(self.prev_btn)
        nav_layout.addWidget(self.page_input)
        nav_layout.addWidget(self.page_label)
        nav_layout.addWidget(self.next_btn)
        nav_layout.addStretch()
        
        # 缩略图切换按钮
        self.thumbnail_toggle_btn = QPushButton("显示缩略图")
        self.thumbnail_toggle_btn.setCheckable(True)
        self.thumbnail_toggle_btn.clicked.connect(self.toggle_thumbnails)
        self.thumbnail_toggle_btn.setToolTip("显示/隐藏页面缩略图")
        nav_layout.addWidget(self.thumbnail_toggle_btn)
        
        # 全屏按钮
        self.fullscreen_btn = QPushButton("全屏 (F11)")
        self.fullscreen_btn.clicked.connect(self.toggle_fullscreen)
        nav_layout.addWidget(self.fullscreen_btn)
        
        layout.addLayout(nav_layout)
        
        # 将预览容器添加到主布局
        main_layout.addWidget(preview_container)
        
        # 提示标签
        tip_label = QLabel("提示: Ctrl+滚轮缩放 | 滚轮翻页 | Ctrl+G跳转 | F11全屏")
        tip_label.setStyleSheet("color: #666; font-size: 10px;")
        tip_label.setAlignment(Qt.AlignCenter)
        layout.addWidget(tip_label)
    
    def eventFilter(self, obj, event):
        """事件过滤器 - 处理滚轮事件"""
        if obj == self.scroll_area.viewport():
            if event.type() == event.Wheel:
                modifiers = QApplication.keyboardModifiers()
                
                # Ctrl + 滚轮 = 缩放
                if modifiers == Qt.ControlModifier:
                    if event.angleDelta().y() > 0:
                        self.zoom_in()
                    else:
                        self.zoom_out()
                    return True
                
                # 普通滚轮 = 翻页
                else:
                    if event.angleDelta().y() > 0:
                        self.prev_page()
                    else:
                        self.next_page()
                    return True
        
        return super().eventFilter(obj, event)
    
    def keyPressEvent(self, event):
        """处理键盘事件 - 支持Ctrl+G跳转"""
        if event.key() == Qt.Key_G and event.modifiers() == Qt.ControlModifier:
            # Ctrl+G: 聚焦到页码输入框
            self.page_input.setFocus()
            self.page_input.selectAll()
        else:
            super().keyPressEvent(event)
    
    def toggle_fullscreen(self):
        """切换主窗口全屏模式 - 使用 window() 方法获取顶层窗口"""
        # 使用 window() 方法自动获取顶层窗口,更可靠
        top_window = self.window()
        if top_window:
            if top_window.isFullScreen():
                top_window.showNormal()
                self.fullscreen_btn.setText("全屏 (F11)")
            else:
                top_window.showFullScreen()
                self.fullscreen_btn.setText("退出全屏 (F11/ESC)")
        else:
            print("错误: 无法获取主窗口")
    
    def zoom_in(self):
        """放大"""
        if self.zoom_level < self.max_zoom:
            old_zoom = self.zoom_level
            self.zoom_level += self.zoom_step
            # 清除旧缩放级别的缓存
            self.page_cache.remove_zoom_level(old_zoom)
            self.render_page()
            self.update_zoom_label()
    
    def zoom_out(self):
        """缩小"""
        if self.zoom_level > self.min_zoom:
            old_zoom = self.zoom_level
            self.zoom_level -= self.zoom_step
            # 清除旧缩放级别的缓存
            self.page_cache.remove_zoom_level(old_zoom)
            self.render_page()
            self.update_zoom_label()
    
    def reset_zoom(self):
        """重置缩放"""
        old_zoom = self.zoom_level
        self.zoom_level = 1.5
        # 清除旧缩放级别的缓存
        if old_zoom != 1.5:
            self.page_cache.remove_zoom_level(old_zoom)
        self.render_page()
        self.update_zoom_label()
    
    def update_zoom_label(self):
        """更新缩放标签"""
        zoom_percent = int((self.zoom_level / 1.5) * 100)
        self.zoom_label.setText(f"{zoom_percent}%")
    
    def jump_to_page(self, page_num):
        """跳转到指定页面"""
        if self.doc is None or self.total_pages == 0:
            return
        
        # 页码从1开始,内部索引从0开始
        target_page = page_num - 1
        
        if 0 <= target_page < self.total_pages:
            self.current_page = target_page
            self.render_page()
    
    def toggle_thumbnails(self, checked):
        """切换缩略图面板显示"""
        self.thumbnail_panel.setVisible(checked)
        if checked:
            self.thumbnail_toggle_btn.setText("隐藏缩略图")
            # 如果缩略图列表为空,则生成缩略图
            if self.thumbnail_list.count() == 0 and self.doc:
                self.generate_thumbnails()
            # 高亮当前页面
            self.highlight_current_thumbnail()
        else:
            self.thumbnail_toggle_btn.setText("显示缩略图")
    
    def generate_thumbnails(self):
        """生成所有页面的缩略图"""
        if not self.doc:
            return
        
        self.thumbnail_list.clear()
        
        # 使用低分辨率渲染缩略图以提高性能
        for page_num in range(self.total_pages):
            page = self.doc[page_num]
            # 缩小到20%以加快渲染速度
            mat = fitz.Matrix(0.2, 0.2)
            pix = page.get_pixmap(matrix=mat)
            
            # 转换为QPixmap
            img = QImage(pix.samples, pix.width, pix.height,
                        pix.stride, QImage.Format_RGB888)
            pixmap = QPixmap.fromImage(img)
            
            # 创建列表项
            item = QListWidgetItem()
            item.setIcon(QIcon(pixmap))
            item.setText(f"第 {page_num + 1} 页")
            item.setData(Qt.UserRole, page_num)  # 存储页码
            item.setTextAlignment(Qt.AlignCenter)
            self.thumbnail_list.addItem(item)
    
    def on_thumbnail_clicked(self, item):
        """点击缩略图跳转到对应页面"""
        page_num = item.data(Qt.UserRole)
        if page_num is not None:
            self.current_page = page_num
            self.render_page()
            self.highlight_current_thumbnail()
    
    def highlight_current_thumbnail(self):
        """高亮当前页面的缩略图"""
        if not self.thumbnail_panel.isVisible():
            return
        
        for i in range(self.thumbnail_list.count()):
            item = self.thumbnail_list.item(i)
            page_num = item.data(Qt.UserRole)
            if page_num == self.current_page:
                self.thumbnail_list.setCurrentItem(item)
                # 确保当前项可见
                self.thumbnail_list.scrollToItem(item)
                break
    
    def load_pdf(self, file_path: str):
        if not HAS_PYMUPDF:
            self.image_label.setText("需要安装 PyMuPDF 才能预览 PDF\npip install pymupdf")
            return
        
        try:
            # 停止正在运行的预加载任务
            if self.preload_worker and self.preload_worker.isRunning():
                self.preload_worker.stop()
                self.preload_worker.wait()
            
            self.doc = fitz.open(file_path)
            self.total_pages = len(self.doc)
            self.current_page = 0
            self.zoom_level = 1.5  # 重置缩放
            
            # 清空页面缓存
            self.page_cache.clear()
            
            # 更新页码输入框范围
            self.page_input.setMaximum(self.total_pages)
            self.page_input.setValue(1)
            
            # 清空缩略图列表(延迟加载)
            self.thumbnail_list.clear()
            
            # 如果缩略图面板可见,重新生成缩略图
            if self.thumbnail_panel.isVisible():
                self.generate_thumbnails()
                self.highlight_current_thumbnail()
            
            self.render_page()
            self.update_zoom_label()
        except Exception as e:
            self.image_label.setText(f"无法加载 PDF: {e}")
    
    def render_page(self):
        if self.doc is None or self.total_pages == 0:
            return
        
        # 尝试从缓存获取
        cached_pixmap = self.page_cache.get(self.current_page, self.zoom_level)
        if cached_pixmap:
            # 缓存命中,直接使用
            self.image_label.setPixmap(cached_pixmap)
            self.image_label.resize(cached_pixmap.size())
        else:
            # 缓存未命中,渲染页面
            page = self.doc[self.current_page]
            mat = fitz.Matrix(self.zoom_level, self.zoom_level)
            pix = page.get_pixmap(matrix=mat)
            
            # 转换为 QImage
            img = QImage(pix.samples, pix.width, pix.height, pix.stride, QImage.Format_RGB888)
            pixmap = QPixmap.fromImage(img)
            
            # 添加到缓存
            self.page_cache.put(self.current_page, self.zoom_level, pixmap)
            
            self.image_label.setPixmap(pixmap)
            self.image_label.resize(pixmap.size())
        
        self.page_label.setText(f"{self.current_page + 1} / {self.total_pages}")
        
        # 同步更新页码输入框(阻止信号避免循环触发)
        self.page_input.blockSignals(True)
        self.page_input.setValue(self.current_page + 1)
        self.page_input.blockSignals(False)
        
        # 同步更新缩略图高亮
        self.highlight_current_thumbnail()
        
        # 触发预加载相邻页面
        self.preload_adjacent_pages()
    
    def preload_adjacent_pages(self):
        """预加载相邻页面以提高翻页性能"""
        if not self.doc or self.total_pages == 0:
            return
        
        # 如果已有预加载任务在运行,先停止
        if self.preload_worker and self.preload_worker.isRunning():
            self.preload_worker.stop()
            self.preload_worker.wait()
        
        # 确定需要预加载的页面(前后各2页)
        pages_to_load = []
        for offset in [-2, -1, 1, 2]:
            page_num = self.current_page + offset
            if 0 <= page_num < self.total_pages:
                # 检查是否已缓存
                if not self.page_cache.get(page_num, self.zoom_level):
                    pages_to_load.append(page_num)
        
        # 如果有需要预加载的页面,启动预加载线程
        if pages_to_load:
            self.preload_worker = PreloadWorker(self.doc, pages_to_load, self.zoom_level)
            self.preload_worker.page_loaded.connect(self.on_page_preloaded)
            self.preload_worker.start()
    
    def on_page_preloaded(self, page_num, zoom_level, pixmap):
        """预加载完成的回调"""
        self.page_cache.put(page_num, zoom_level, pixmap)
    
    def prev_page(self):
        if self.current_page > 0:
            self.current_page -= 1
            self.render_page()
    
    def next_page(self):
        if self.current_page < self.total_pages - 1:
            self.current_page += 1
            self.render_page()
    
    def clear(self):
        # 停止预加载任务
        if self.preload_worker and self.preload_worker.isRunning():
            self.preload_worker.stop()
            self.preload_worker.wait()
        
        if self.doc:
            self.doc.close()
            self.doc = None
        self.total_pages = 0
        self.current_page = 0
        self.zoom_level = 1.5
        
        # 清空页面缓存
        self.page_cache.clear()
        
        self.image_label.clear()
        self.image_label.setText("请选择 PDF 文件")
        self.page_label.setText("0 / 0")
        self.update_zoom_label()
        
        # 清空缩略图列表
        self.thumbnail_list.clear()
        # 隐藏缩略图面板
        if self.thumbnail_panel.isVisible():
            self.thumbnail_toggle_btn.setChecked(False)
            self.toggle_thumbnails(False)


